const output = [];
for (let i = 0; i < $input.all().length; i++) {
  const item = $input.all()[i];
  try {
    const buffer = await this.helpers.getBinaryDataBuffer(i, 'data');
    const text = buffer.toString('utf8').replace(/^\uFEFF/, '');
    output.push({
      json: {
        ...item.json,
        "manifest": JSON.parse(text),
      },
      binary: item.binary,
      pairedItem: { item: i },
    });
  } catch (error) {
    if (item.json && item.json.error) {
      output.push({ json: item.json, binary: item.binary, pairedItem: { item: i } });
      continue;
    }
    throw error;
  }
}
return output;

const manifest = $json.manifest || {};

function normalizeSlashes(value) {
  return String(value).replace(/\\/g, '/');
}

function toContainerPath(value) {
  if (!value) return null;

  var normalized = normalizeSlashes(value);

  if (normalized.indexOf('./') === 0) {
    normalized = normalized.slice(2);
  }

  if (normalized.indexOf('/files/') === 0) {
    return normalized;
  }

  if (normalized.indexOf('shared/') === 0) {
    return '/files/' + normalized.slice('shared/'.length);
  }

  if (normalized.charAt(0) === '/') {
    return normalized;
  }

  return '/files/' + normalized;
}

function toRepoRelative(value) {
  if (!value) return null;

  var normalized = normalizeSlashes(value);

  if (normalized.indexOf('/files/') === 0) {
    return 'shared/' + normalized.slice('/files/'.length);
  }

  return normalized;
}

function dirname(value) {
  if (!value) return null;
  var normalized = normalizeSlashes(value).replace(/\/$/, '');
  var idx = normalized.lastIndexOf('/');
  return idx === -1 ? null : normalized.slice(0, idx);
}

const validationErrors = [];

if (!manifest.job_id) validationErrors.push('job_id kosong');
if (manifest.status !== 'ready') validationErrors.push('status harus ready');
if (!manifest.clip_path) validationErrors.push('clip_path kosong');
if (!Array.isArray(manifest.clips) || manifest.clips.length === 0) validationErrors.push('clips kosong');
if (!Array.isArray(manifest.platform_targets) || manifest.platform_targets.length === 0) validationErrors.push('platform_targets kosong');
if (!manifest.approval_mode) validationErrors.push('approval_mode kosong');

const clipPathRepo = toRepoRelative(manifest.clip_path);
const clipPathAbs = toContainerPath(manifest.clip_path);
const jobDirAbs = dirname(clipPathAbs);
const manifestPath = jobDirAbs ? (jobDirAbs + '/manifest.json') : '/files/ready/unknown/manifest.json';
const intakeResultPath = jobDirAbs ? (jobDirAbs + '/intake_result.json') : '/files/ready/unknown/intake_result.json';

return {
  json: {
    manifest_path: manifestPath,
    intake_result_path: intakeResultPath,
    workflow_status: validationErrors.length === 0 ? 'valid' : 'invalid',
    validation_errors: validationErrors,
    job_id: manifest.job_id || null,
    status: manifest.status || null,
    approval_mode: manifest.approval_mode || null,
    platform_targets: manifest.platform_targets || [],
    clip_path: clipPathRepo,
    clip_path_abs: clipPathAbs,
    transcript_path_abs: toContainerPath(manifest.transcript_path),
    thumbnail_path_abs: toContainerPath(manifest.thumbnail_path),
    clips: (manifest.clips || []).map(function (clip, index) {
      return {
        clip_id: clip.clip_id || ('clip_' + (index + 1)),
        file_name: clip.file_name || null,
        clip_path: clip.clip_path || null,
        clip_path_abs: toContainerPath(clip.clip_path)
      };
    }),
    manifest: manifest
  }
};

const checkedAt = new Date().toISOString();
const result = {
  job_id: $json.job_id,
  stage: 'WF-01_INTAKE',
  status: 'ASSETS_VALID',
  checked_at: checkedAt,
  manifest_path: String($json.manifest_path || '').replace(/^\/files\//, 'shared/'),
  clip_path: $json.clip_path || null,
  validation_errors: [],
  platform_targets: $json.platform_targets || []
};
const content = JSON.stringify(result, null, 2) + '\n';
return {
  json: Object.assign({}, $json, {
    intake_result_status: result.status,
    intake_result_payload: result
  }),
  binary: {
    data: {
      data: Buffer.from(content, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: 'intake_result.json'
    }
  }
};

const checkedAt = new Date().toISOString();
const manifestPath = $json.manifest_path || null;
const result = {
  job_id: $json.job_id || null,
  stage: 'WF-01_INTAKE',
  status: 'ASSETS_INVALID',
  checked_at: checkedAt,
  manifest_path: manifestPath ? String(manifestPath).replace(/^\/files\//, 'shared/') : null,
  clip_path: $json.clip_path || null,
  validation_errors: $json.validation_errors || ['Manifest invalid tanpa detail'],
  platform_targets: $json.platform_targets || []
};
const content = JSON.stringify(result, null, 2) + '\n';
return {
  json: Object.assign({}, $json, {
    intake_result_status: result.status,
    intake_result_payload: result
  }),
  binary: {
    data: {
      data: Buffer.from(content, 'utf8').toString('base64'),
      mimeType: 'application/json',
      fileName: 'intake_result.json'
    }
  }
};

const binaryFieldName = $binary ? Object.keys($binary)[0] : null;
const currentErrors = Array.isArray($json.validation_errors) ? [...$json.validation_errors] : [];
const clipReadOk = Boolean(binaryFieldName);
if (!clipReadOk) {
  currentErrors.push('clip utama tidak dapat dibaca dari path: ' + String($json.clip_path_abs || $json.clip_path || 'unknown'));
}
return {
  json: {
    ...$json,
    clip_read_ok: clipReadOk,
    validation_errors: currentErrors,
  },
  binary: $binary || undefined,
};
